+namespace
+{
+std::array<float, 2> rotateNedXY(const std::array<float, 2> & xy, float yaw)
+{
+  const float c = std::cos(yaw);
+  const float s = std::sin(yaw);
+  return {(c * xy[0]) - (s * xy[1]), (s * xy[0]) + (c * xy[1])};
+}
